import { useState } from "react";
import axios from "axios";

const API_BASE_URL = "http://localhost:8080/api";

export default function LoginPage({ setPage, setUser, onBack }) {
  const [showPass, setShowPass] = useState(false);
  const [email, setEmail] = useState("");
  const [pass, setPass] = useState("");
  const [remember, setRemember] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleLogin = async () => {
    if (!email || !pass) {
      setError("Please fill in all fields");
      return;
    }

    setLoading(true);
    setError("");

    try {
      const response = await axios.post(`${API_BASE_URL}/users/login`, {
        email,
        password: pass
      });

      if (response.data.success) {
        const { token, user } = response.data.data;
        localStorage.setItem("token", token);
        localStorage.setItem("user", JSON.stringify(user));
        setUser(user);

        if (user.role === "admin") setPage("admin-dashboard");
        else if (user.role === "chef") setPage("chef-dashboard");
        else setPage("user-dashboard");
      }
    } catch (err) {
      console.error("Login error:", err);
      setError(err.response?.data?.message || "Login failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-split">
      {/* Visual Side */}
      <div className="auth-visual">
        <img src="https://images.unsplash.com/photo-1540189549336-e6e99c3679fe?w=800&h=1200&fit=crop" alt="Delicious Food" />
        <div className="auth-visual-overlay" />
        <div className="auth-visual-text">
          <h2 className="serif">Discover the art <br /> of home cooking.</h2>
          <p>Join thousands of food enthusiasts sharing their secret family recipes every day.</p>
        </div>
      </div>

      {/* Form Side */}
      <div className="auth-panel" style={{ position: "relative" }}>
        {/* Back Button */}
        <button 
          onClick={onBack} 
          style={{ 
            position: "absolute", 
            top: "40px", 
            left: "40px", 
            background: "none", 
            border: "none", 
            color: "var(--text-muted)", 
            fontSize: "14px", 
            fontWeight: "600",
            display: "flex",
            alignItems: "center",
            gap: "8px"
          }}
        >
          <span>←</span> Back
        </button>

        <div className="auth-logo" style={{ marginBottom: "48px" }}>
          <div className="auth-logo-icon">🍽</div>
          <span className="auth-logo-text">RecipeNest</span>
        </div>

        <h1 className="auth-heading">Welcome back</h1>
        <p className="auth-subheading">Please enter your details to sign in to your account.</p>

        {error && (
          <div style={{ background: "#fef2f2", color: "#dc2626", padding: "12px 16px", borderRadius: "var(--radius-md)", marginBottom: "24px", fontSize: "14px", border: "1px solid #fee2e2" }}>
            {error}
          </div>
        )}

        <div className="field-wrap">
          <label className="field-label">Email Address</label>
          <div style={{ position: "relative" }}>
            <span className="field-icon">✉</span>
            <input
              className="field-input"
              type="email"
              placeholder="name@company.com"
              value={email}
              onChange={e => setEmail(e.target.value)}
              disabled={loading}
            />
          </div>
        </div>

        <div className="field-wrap">
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "6px" }}>
            <label className="field-label" style={{ margin: 0 }}>Password</label>
            <button className="btn-ghost" onClick={() => setPage("forgot-password")} style={{ fontSize: "12px" }}>Forgot password?</button>
          </div>
          <div style={{ position: "relative" }}>
            <span className="field-icon">🔒</span>
            <input
              className="field-input"
              type={showPass ? "text" : "password"}
              placeholder="••••••••"
              value={pass}
              onChange={e => setPass(e.target.value)}
              disabled={loading}
            />
            <button className="field-eye" onClick={() => setShowPass(v => !v)} disabled={loading}>
              {showPass ? "🙈" : "👁"}
            </button>
          </div>
        </div>

        <div style={{ display: "flex", alignItems: "center", gap: "8px", fontSize: "14px", color: "#475569", marginBottom: "32px" }}>
          <input
            type="checkbox"
            id="remember"
            checked={remember}
            onChange={e => setRemember(e.target.checked)}
            disabled={loading}
            style={{ width: "16px", height: "16px", cursor: "pointer" }}
          />
          <label htmlFor="remember" style={{ cursor: "pointer" }}>Remember me for 30 days</label>
        </div>

        <button
          className="btn-primary"
          onClick={handleLogin}
          disabled={loading}
          style={{ padding: "14px", fontSize: "15px", marginBottom: "24px" }}
        >
          {loading ? "Signing in..." : "Login"}
        </button>

        <div className="auth-divider">or continue with</div>

        <button className="btn-secondary" style={{ padding: "12px", fontSize: "14px", marginBottom: "32px" }} disabled={loading}>
          <img src="https://www.google.com/favicon.ico" alt="G" width={18} />
          Sign in with Google
        </button>

        <div className="auth-footer">
          Don't have an account? <button onClick={() => setPage("signup")} style={{ fontWeight: "700" }}>Sign up</button>
        </div>
      </div>
    </div>
  );
}
